arrayPipelines.data:
[
	{
		$match: {{ question_answered_filter_js.getMatchQuery() }}
	},
		{ $unwind: "$response.answers" },
	{
		$project: {
			_id: 1,
			eventId: 1,
			orgQuery: 1,
			cleaned_query: 1,
			instruction: 1,
			created: 1,
			clientId: 1,
			userId: 1,
			generateSource: 1,
			generationFlow: 1,
			tx_consumed: 1,
			answerText: "$response.answers.text",
			score: "$response.answers.score",
			partialAnswer: "$response.answers.partialAnswer",
			preference: 1
			answerSources: {
			$map: {
			input: "$response.answers.sources",
			as: "source",
			in: "$$source.name",
		},
	},
	}
	},
	{ $sort: { _id: -1, score: -1 } },
]

